import java.io.*;

public class ReadSerial extends ObjectInputStream {
    public ReadSerial(InputStream in) throws IOException {
        super(in);
    }

    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) throws IOException, ClassNotFoundException {
        System.out.println("Class: " + desc.getName());
        System.out.println("UID: " + desc.getSerialVersionUID());
        return super.resolveClass(desc);
    }

    public static void main(String[] args) throws Exception {
        try {
            ReadSerial ois = new ReadSerial(new FileInputStream("data/test/MultiValueMap.emptyCollection.version3.3.obj"));
            ois.readObject();
        } catch (Exception e) {
            // ignore
        }
    }
}
